// ===== КОНФИГУРАЦИЯ — ЗАПОЛНИ СВОИ ДАННЫЕ =====
const AVITO_CLIENT_ID = 'ВСТАВЬ_CLIENT_ID';
const AVITO_CLIENT_SECRET = 'ВСТАВЬ_CLIENT_SECRET';
const AVITO_USER_ID = 'ВСТАВЬ_USER_ID'; // Твой user_id в Avito
const TG_BOT_TOKEN = '7537534483:ВСТАВЬ_ТОКЕН_БОТА';
const TG_CHAT_ID = '25862920'; // Евгений
const AI_API_KEY = ''; // Claude API key (опционально)
// ===============================================

const staticData = $getWorkflowStaticData('global');
const now = Date.now();

// --- 1. Получить OAuth token ---
if (!staticData.avito_token || !staticData.avito_token_expires || staticData.avito_token_expires < now + 300000) {
  try {
    const tokenResp = await $helpers.httpRequest({
      method: 'POST',
      url: 'https://api.avito.ru/token/',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: `grant_type=client_credentials&client_id=${AVITO_CLIENT_ID}&client_secret=${AVITO_CLIENT_SECRET}`,
      returnFullResponse: false
    });
    staticData.avito_token = tokenResp.access_token;
    staticData.avito_token_expires = now + ((tokenResp.expires_in || 86400) * 1000);
  } catch (e) {
    return [{ json: { error: 'Auth failed: ' + e.message, _stop: true } }];
  }
}
const token = staticData.avito_token;

// --- 2. Получить непрочитанные чаты ---
let chats = [];
try {
  const chatsResp = await $helpers.httpRequest({
    method: 'GET',
    url: `https://api.avito.ru/messenger/v2/accounts/${AVITO_USER_ID}/chats`,
    headers: { 'Authorization': `Bearer ${token}` },
    qs: { unread_only: true, limit: 20 }
  });
  chats = chatsResp.chats || chatsResp.result?.chats || [];
} catch (e) {
  return [{ json: { error: 'Get chats failed: ' + e.message, _stop: true } }];
}

if (!chats.length) {
  return [{ json: { _stop: true, reason: 'no_unread' } }];
}

// --- 3. Фильтр уже обработанных ---
if (!staticData.seen) staticData.seen = {};

// Чистим старые записи (старше 24ч)
const cutoff = now - 86400000;
for (const key of Object.keys(staticData.seen)) {
  if (staticData.seen[key] < cutoff) delete staticData.seen[key];
}

const newMessages = [];

for (const chat of chats) {
  const chatId = chat.id || chat.chat_id;
  if (!chatId) continue;

  // Получить последние сообщения в чате
  let messages = [];
  try {
    const msgResp = await $helpers.httpRequest({
      method: 'GET',
      url: `https://api.avito.ru/messenger/v3/accounts/${AVITO_USER_ID}/chats/${chatId}/messages/`,
      headers: { 'Authorization': `Bearer ${token}` },
      qs: { limit: 5 }
    });
    messages = msgResp.messages || msgResp.result?.messages || [];
  } catch (e) {
    continue; // Пропускаем чат при ошибке
  }

  // Найти новые входящие сообщения
  for (const msg of messages) {
    const msgId = String(msg.id || msg.message_id || '');
    const authorId = String(msg.author_id || msg.user_id || '');

    // Пропускаем свои сообщения и уже обработанные
    if (authorId === AVITO_USER_ID) continue;
    if (msgId && staticData.seen[msgId]) continue;

    // Помечаем как обработанное
    if (msgId) staticData.seen[msgId] = now;

    // Получить информацию о товаре
    let itemInfo = { title: 'Неизвестный товар', price: '—', url: '' };
    const itemId = chat.item_id || chat.context?.value?.item_id || '';
    if (itemId) {
      try {
        const itemResp = await $helpers.httpRequest({
          method: 'GET',
          url: `https://api.avito.ru/core/v1/accounts/${AVITO_USER_ID}/items/${itemId}/`,
          headers: { 'Authorization': `Bearer ${token}` }
        });
        itemInfo = {
          title: itemResp.title || 'Товар',
          price: itemResp.price ? `${itemResp.price} ₽` : '—',
          url: itemResp.url || `https://www.avito.ru/${itemId}`
        };
      } catch (e) { /* оставляем дефолт */ }
    }

    newMessages.push({
      json: {
        chat_id: chatId,
        message_id: msgId,
        buyer_name: chat.user?.name || msg.author_name || 'Покупатель',
        message_text: msg.content?.text || msg.text || msg.body || '(без текста)',
        item_title: itemInfo.title,
        item_price: itemInfo.price,
        item_url: itemInfo.url,
        item_id: itemId,
        avito_user_id: AVITO_USER_ID,
        tg_bot_token: TG_BOT_TOKEN,
        tg_chat_id: TG_CHAT_ID,
        ai_api_key: AI_API_KEY,
        _stop: false
      }
    });

    break; // Берём только последнее новое сообщение в чате
  }
}

if (newMessages.length === 0) {
  return [{ json: { _stop: true, reason: 'all_seen' } }];
}

return newMessages;

const item = $input.first().json;

// Контекст для AI
const prompt = `Ты — менеджер сервисного центра Jabuka (ремонт Apple техники) на Avito.
Покупатель написал сообщение по объявлению.

Объявление: ${item.item_title} — ${item.item_price}
Имя покупателя: ${item.buyer_name}
Сообщение: ${item.message_text}

Напиши короткий, дружелюбный ответ (1-3 предложения).
Если спрашивают о наличии — подтверди что товар есть.
Если спрашивают о состоянии — скажи что отличное, проверено.
Если спрашивают о доставке — предложи самовывоз или курьера.
Если спрашивают о скидке — скажи что цена финальная, но можно обсудить.
Не используй смайлики. Будь кратким и конкретным.`;

return [{
  json: {
    ...item,
    ai_prompt: prompt
  }
}];

const item = $input.first().json;
const prev = $node['Build AI Prompt'].json;

// Извлекаем ответ AI
let draft = '(AI недоступен — ответьте вручную)';
try {
  if (item.content && item.content[0] && item.content[0].text) {
    draft = item.content[0].text;
  } else if (item.error) {
    draft = '(AI ошибка: ' + (item.error.message || 'unknown') + ')';
  }
} catch (e) {
  draft = '(AI ошибка парсинга)';
}

// Формируем Telegram сообщение
const tgText = `📦 <b>Новое сообщение Avito</b>\n\n` +
  `👤 <b>${prev.buyer_name}</b>\n` +
  `📋 ${prev.item_title} — ${prev.item_price}\n\n` +
  `💬 <i>${prev.message_text}</i>\n\n` +
  `───────────────\n` +
  `🤖 <b>Черновик ответа:</b>\n${draft}\n` +
  `───────────────`;

// Inline keyboard с кнопками
const keyboard = {
  inline_keyboard: [
    [
      { text: '✅ Отправить черновик', callback_data: `avito:approve:${prev.chat_id}` },
      { text: '✏️ Свой ответ', callback_data: `avito:custom:${prev.chat_id}` }
    ],
    [
      { text: '🔗 Открыть в Avito', url: prev.item_url || 'https://avito.ru' }
    ]
  ]
};

// Сохраняем черновик в static data для approve
const staticData = $getWorkflowStaticData('global');
if (!staticData.drafts) staticData.drafts = {};
staticData.drafts[prev.chat_id] = {
  text: draft,
  buyer: prev.buyer_name,
  item: prev.item_title,
  ts: Date.now()
};

return [{
  json: {
    tg_url: `https://api.telegram.org/bot${prev.tg_bot_token}/sendMessage`,
    body: {
      chat_id: prev.tg_chat_id,
      text: tgText,
      parse_mode: 'HTML',
      reply_markup: keyboard
    }
  }
}];

// ===== КОНФИГУРАЦИЯ (дублируй сюда) =====
const AVITO_CLIENT_ID = 'ВСТАВЬ_CLIENT_ID';
const AVITO_CLIENT_SECRET = 'ВСТАВЬ_CLIENT_SECRET';
const AVITO_USER_ID = 'ВСТАВЬ_USER_ID';
const TG_BOT_TOKEN = '7537534483:ВСТАВЬ_ТОКЕН_БОТА';
// ==========================================

const body = $input.first().json.body || $input.first().json;

// Данные из callback: action, chat_id, text, tg_message_id, tg_chat_id
const action = body.action || 'approve'; // approve | custom | send_custom
const chatId = body.chat_id || body.avito_chat_id;
const customText = body.text || '';
const tgMessageId = body.tg_message_id || '';
const tgChatId = body.tg_chat_id || '25862920';
const callbackQueryId = body.callback_query_id || '';

if (!chatId) {
  return [{ json: { error: 'chat_id is required', _stop: true } }];
}

// Получить OAuth token
const staticData = $getWorkflowStaticData('global');
const now = Date.now();

if (!staticData.avito_token || !staticData.avito_token_expires || staticData.avito_token_expires < now + 300000) {
  const tokenResp = await $helpers.httpRequest({
    method: 'POST',
    url: 'https://api.avito.ru/token/',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: `grant_type=client_credentials&client_id=${AVITO_CLIENT_ID}&client_secret=${AVITO_CLIENT_SECRET}`
  });
  staticData.avito_token = tokenResp.access_token;
  staticData.avito_token_expires = now + ((tokenResp.expires_in || 86400) * 1000);
}
const token = staticData.avito_token;

// Определить текст ответа
let replyText = customText;
if (action === 'approve') {
  // Берём сохранённый черновик
  const drafts = staticData.drafts || {};
  const draft = drafts[chatId];
  if (draft && draft.text) {
    replyText = draft.text;
    delete drafts[chatId]; // Очищаем после использования
  } else {
    return [{ json: { error: 'Draft not found for chat ' + chatId, _stop: true } }];
  }
}

if (!replyText) {
  return [{ json: { error: 'No reply text', _stop: true } }];
}

// Отправить ответ в Avito
try {
  await $helpers.httpRequest({
    method: 'POST',
    url: `https://api.avito.ru/messenger/v1/accounts/${AVITO_USER_ID}/chats/${chatId}/messages`,
    headers: {
      'Authorization': `Bearer ${token}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      message: { text: replyText },
      type: 'text'
    })
  });
} catch (e) {
  return [{ json: { error: 'Send to Avito failed: ' + e.message, _stop: true } }];
}

// Подтвердить в Telegram — ответить на callback_query и обновить сообщение
if (callbackQueryId) {
  try {
    await $helpers.httpRequest({
      method: 'POST',
      url: `https://api.telegram.org/bot${TG_BOT_TOKEN}/answerCallbackQuery`,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        callback_query_id: callbackQueryId,
        text: '✅ Ответ отправлен в Avito!'
      })
    });
  } catch (e) { /* не критично */ }
}

// Отредактировать TG сообщение — добавить метку "отправлено"
if (tgMessageId && tgChatId) {
  try {
    await $helpers.httpRequest({
      method: 'POST',
      url: `https://api.telegram.org/bot${TG_BOT_TOKEN}/editMessageReplyMarkup`,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        chat_id: tgChatId,
        message_id: tgMessageId,
        reply_markup: {
          inline_keyboard: [
            [{ text: '✅ Отправлено в Avito', callback_data: 'avito:done' }]
          ]
        }
      })
    });
  } catch (e) { /* не критично */ }
}

return [{
  json: {
    success: true,
    action: action,
    chat_id: chatId,
    reply_text: replyText,
    _stop: false
  }
}];

